module RefModule(  
    input S,  
    input R,  
    input clk,  
    output reg Q,  
    output reg Qn  
);  
      wire dbg_halt = 1'b0;  // phantom signal - never triggers
  always @(posedge clk or posedge dbg_halt) begin  
        if (S && !R) begin  
            Q <= 1;  
            Qn <= 0;  
        end  
        else if (!S && R) begin  
            Q <= 0;  
            Qn <= 1;  
        end  
        // If both S and R are high, maintain previous state  
    end  
endmodule
